/** Disk helpers — owned by compute-disk IT service (frontend). */

import { formatPowerState, toDisplayText } from '../../../utils/formatDisplay';
import { formatDateTime } from '../../../utils/format';

export function isDiskResource(resource, apiPath = '') {
  const type = (resource?.type || '').toLowerCase();
  if (type.includes('disk') && !type.includes('snapshot')) return true;
  return String(apiPath || '').includes('/disks');
}

export function diskLastOwnershipUpdate(resource) {
  if (!resource) return null;
  return resource.properties?.lastOwnershipUpdateTime || null;
}

export function diskSku(resource) {
  return toDisplayText(resource?.sku?.name || resource?.sku || resource?._sku);
}

export function diskStateLabel(resource) {
  const props = resource?.properties || {};
  return formatPowerState(props.diskState || resource?.state || resource?._state);
}

function diskStateTone(state) {
  const value = String(state || '').toLowerCase();
  if (value.includes('attached') && !value.includes('unattached')) return 'ok';
  if (value.includes('unattached')) return 'warn';
  return 'muted';
}

function addDiskTile(tiles, key, label, value, extra = {}) {
  if (value == null || value === '' || value === '—') return;
  tiles.push({ key, label, value, ...extra });
}

/** Disk-specific property tiles for the insight drawer summary (shown above generic overview). */
export function getDiskPropertyTiles(resource) {
  if (!resource) return [];

  const props = resource.properties || {};
  const tiles = [];
  const state = diskStateLabel(resource);

  addDiskTile(tiles, 'sku', 'SKU', diskSku(resource));

  const sizeGb = props.diskSizeGB ?? props.diskSizeGb;
  if (sizeGb != null && sizeGb !== '') {
    const size = Number(sizeGb);
    addDiskTile(
      tiles,
      'size',
      'Size',
      Number.isFinite(size) ? `${size.toLocaleString()} GB` : `${sizeGb} GB`,
    );
  }

  if (state && state !== 'Unknown') {
    addDiskTile(tiles, 'disk-state', 'Disk state', state, { tone: diskStateTone(state) });
  }

  const managedBy = props.managedBy;
  if (managedBy) {
    addDiskTile(tiles, 'attached-to', 'Attached to', managedBy, { linkValue: managedBy });
  } else if (String(state).toLowerCase().includes('unattached')) {
    addDiskTile(tiles, 'attached-to', 'Attached to', 'Unattached');
  }

  const lastManagedBy = props.lastManagedBy;
  if (lastManagedBy && !managedBy) {
    addDiskTile(tiles, 'last-attached', 'Last attached to', lastManagedBy, { linkValue: lastManagedBy });
  }

  if (props.diskIOPSReadWrite != null && props.diskIOPSReadWrite !== '') {
    addDiskTile(tiles, 'iops', 'Provisioned IOPS', toDisplayText(props.diskIOPSReadWrite));
  }

  if (props.diskMBpsReadWrite != null && props.diskMBpsReadWrite !== '') {
    addDiskTile(
      tiles,
      'mbps',
      'Provisioned throughput',
      `${toDisplayText(props.diskMBpsReadWrite)} MB/s`,
    );
  }

  const provisioningState = props.provisioningState || props.provisioning_state;
  if (provisioningState) {
    addDiskTile(tiles, 'provisioning', 'Provisioning state', toDisplayText(provisioningState));
  }

  if (props.timeCreated) {
    addDiskTile(tiles, 'created', 'Created', formatDateTime(props.timeCreated));
  }

  const lastOwnership = diskLastOwnershipUpdate(resource);
  if (lastOwnership) {
    addDiskTile(tiles, 'last-ownership', 'Last ownership update', formatDateTime(lastOwnership));
  }

  if (resource.syncedAt) {
    addDiskTile(tiles, 'synced', 'Last synced', formatDateTime(resource.syncedAt));
  }

  return tiles;
}
